function solve(nums1, nums0) {
    const MOD = 10**9 + 7;
    const n = nums1.length;

    // 1. Determine the sorting criterion for the fragments.
    // A fragment F1 is "greater" than fragment F2 if placing F1 before F2
    // results in a larger total binary string value.
    // This is equivalent to comparing the ratio: (ones_count) / (total_length).
    // More precisely, for two fragments F_i and F_j, F_i comes before F_j if:
    // F_i * (2^(len_j)) > F_j * (2^(len_i))  (This is complex due to length difference)

    // A simpler greedy approach: compare the value of the two fragments shifted.
    // If we have fragments A and B. We compare A+B vs B+A.
    // A = 1...10...0 (nums1[i] ones, nums0[i] zeros)
    // B = 1...10...0 (nums1[j] ones, nums0[j] zeros)

    // We want to sort them such that if A comes before B, A+B > B+A.
    // This is the standard lexicographical comparison for this problem type.

    // Let's create pairs representing the fragments and their structure.
    const fragments = [];
    for (let i = 0; i < n; i++) {
        fragments.push({
            ones: nums1[i],
            zeros: nums0[i],
            // String representation for easy comparison, although we will use numerical comparison later.
            // We don't actually need the string, just the relative order.
        });
    }

    // Custom comparison function for sorting.
    // We want to sort such that if compare(a, b) < 0, 'a' comes before 'b'.
    // 'a' should come before 'b' if (a+b) > (b+a).
    const compareFragments = (a, b) => {
        // Let a have (ones_a, zeros_a) and b have (ones_b, zeros_b).
        // String a: 1^ones_a 0^zeros_a
        // String b: 1^ones_b 0^zeros_b

        // Concatenation a+b: 1^ones_a 0^zeros_a 1^ones_b 0^zeros_b
        // Concatenation b+a: 1^ones_b 0^zeros_b 1^ones_a 0^zeros_a

        // We need to compare the value of a+b and b+a.

        // Since the total length is manageable (<= 2*10^5), we can construct the numbers
        // using BigInt to perform the comparison accurately, as standard JS numbers might lose precision.

        const strA = '1'.repeat(a.ones) + '0'.repeat(a.zeros);
        const strB = '1'.repeat(b.ones) + '0'.repeat(b.zeros);

        const strAB = strA + strB;
        const strBA = strB + strA;

        // BigInt comparison
        if (BigInt('0b' + strAB) > BigInt('0b' + strBA)) {
            // a+b is larger, so a should come before b. Return -1 for ascending sort order 
            // if we interpret '< 0' as 'a comes first'.
            return -1; 
        } else if (BigInt('0b' + strAB) < BigInt('0b' + strBA)) {
            // b+a is larger, so b should come before a. Return 1.
            return 1;
        } else {
            return 0;
        }
    };

    // Sort the fragments using the custom comparator
    fragments.sort(compareFragments);

    // 2. Construct the final result modulo 10^9 + 7
    let result = 0n; // Use BigInt for intermediate calculation
    let powerOf2 = 1n; // Represents 2^k for the current position

    // Iterate through the sorted fragments and calculate the contribution of each fragment.
    for (const frag of fragments) {
        const ones = frag.ones;
        const zeros = frag.zeros;

        // The fragment is 1^ones 0^zeros.
        // The value contributed by the '1's part is: 
        // (2^(zeros + ones) - 2^zeros)

        // A segment of 'k' ones (1^k) contributes 2^k - 1 to its own value.
        // Since this segment is followed by 'zeros' zeros, its weight is shifted by zeros places.
        // The value of 1^ones is (2^ones - 1). This value is multiplied by 2^zeros.

        // Contribution from 1^ones: (2^ones - 1) * 2^zeros
        // 1. Calculate 2^ones - 1 (value of 1^ones)
        let valOnes = (2n ** BigInt(ones)) - 1n;

        // 2. Shift left by 'zeros' positions: * 2^zeros
        let contribution = valOnes * (2n ** BigInt(zeros));

        // Add this contribution to the result
        result = (result + contribution) % BigInt(MOD);
    }

