    * @param nums1 Array of '1' counts for each segment.
    * @param nums0 Array of '0' counts for each segment.
    * @return The maximum integer value modulo 10^9 + 7.
    */
  def solve(nums1: Array[Long], nums0: Array[Long]): Long = {
    val MOD: Long = 1_000_000_007L

    // Define a case class or tuple to hold segment information
    case class Fragment(ones: Long, zeros: Long)

    // 1. Create fragments
    val fragments = (0 until nums1.length).map { i =>
      Fragment(nums1(i), nums0(i))
    }.toMutableList

    // 2. Custom sorting logic: a comes before b if (a+b) > (b+a)
    // We use a custom comparator based on string comparison of concatenated binary representations.
    fragments.sortWith { (a: Fragment, b: Fragment) =>
      // Construct strings representing the fragments
      val strA = "1" * a.ones.toInt + "0" * a.zeros.toInt
      val strB = "1" * b.ones.toInt + "0" * b.zeros.toInt

      // Concatenations
      val strAB = strA + strB
      val strBA = strB + strA

      // Since the total length can be up to 2*10^5, we must use BigInt for comparison accuracy.
      // Scala's BigInt handles large numbers.
      try {
        val valAB = BigInt(strAB, 2)
        val valBA = BigInt(strBA, 2)

        // We want descending order (a before b if a+b > b+a).
        // compare(x, y): returns negative if x < y, zero if x == y, positive if x > y.
        // To achieve descending order for (a+b) vs (b+a), we want:
        // if a+b > b+a, return negative (a comes first).
        val comparison = valAB.compareTo(valBA)

        if (comparison > 0) -1 // a+b is larger, so a comes first
        else if (comparison < 0) 1 // b+a is larger, so b comes first
        else 0
      } catch {
        case e: Exception => 
          // Fallback or error handling if string conversion fails unexpectedly, though unlikely given constraints
          0 
      }
    }

    // 3. Calculate the total value modulo MOD
    var result: BigInt = BigInt(0)

    for (frag <- fragments) {
      val ones = frag.ones
      val zeros = frag.zeros

      // The fragment value is 1^ones 0^zeros.
      // The value of 1^ones is 2^ones - 1.
      // Since this is followed by 'zeros' zeros, its value is shifted left by 'zeros' positions.
      // Contribution = (2^ones - 1) * 2^zeros

      // Calculate 2^ones - 1 (BigInt)
      val valOnes = (BigInt(2) ** BigInt(ones)) - BigInt(1)

      // Calculate 2^zeros (BigInt)
      val powerOfTwoZeros = BigInt(2) ** BigInt(zeros)

      // Contribution = valOnes * powerOfTwoZeros
      var contribution = valOnes * powerOfTwoZeros

      // Add to result, applying modulo at each step to prevent overflow (though BigInt handles size, we need the final modulo)
      result = (result + contribution) % BigInt(MOD)
    }

    result.toLong
  }
}
